import subprocess, re

def ping_host(hostname):
    if not re.match(r'^[a-zA-Z0-9._-]+$', hostname):
        return 'Invalid hostname'
    result = subprocess.run(
        ['ping', '-c', '1', hostname],
        capture_output=True, text=True, timeout=5
    )
    return result.stdout + result.stderr
